                        'Project_Name': pname,
                        'Funding_Source': record.get('Funding_Source'),
                        'Amount': int(record.get('Amount', 0))
                    })

# Remove duplicates
unique_projects = []
seen_names = set()
for p in park_2022_projects:
    if p['Project_Name'] not in seen_names:
