import json
import re

# Load data
with open(str(var_functions.query_db:19), 'r') as f:
    park_funding = json.load(f)

with open(str(var_functions.query_db:18), 'r') as f:
    civic_docs = json.load(f)

# Build funding lookup
funding_lookup = {}
for item in park_funding:
    funding_lookup[item['Project_Name']] = item

# Find completed 2022 park projects
completed_parks = []
seen = set()

for doc in civic_docs:
    text = doc.get('text', '')
    if not text:
        continue

    # Look for completion mentions with 2022
    completion_pattern = re.compile(r'completed[^\n]*2022|2022[^\n]*completed', re.IGNORECASE)

    if completion_pattern.search(text):
        # Check each park project
        for proj_name, fund_info in funding_lookup.items():
            if proj_name in seen:
                continue

            if proj_name in text:
                # Verify it's actually completed in 2022
                lines = text.split('\n')
                for i in range(len(lines)):
                    if proj_name in lines[i] or (i > 0 and proj_name in lines[i-1]):
                        # Check surrounding lines for completion
                        for j in range(max(0, i-5), min(len(lines), i+6)):
                            if 'completed' in lines[j].lower() and '2022' in lines[j]:
                                completed_parks.append({
                                    'Project_Name': proj_name,
                                    'Funding_Source': fund_info['Funding_Source'],
                                    'Amount': int(fund_info['Amount'])
                                })
                                seen.add(proj_name)
                                break

# Calculate total
total = sum(p['Amount'] for p in completed_parks)

result = {
    'total_funding': total,
    'count': len(completed_parks),
    'projects': completed_parks
}

print('__RESULT__:')
print(json.dumps(result))

